mapper.select:
		/*
             SQL ID : SeminarHstyDAO.select
            	 설  명 : 세미나 참석 기록 정보 조회
         */

         AND SEMINAR_HSTY_ID = #{seminarHstyId}

		/*
             SQL ID : SeminarHstyDAO.list
            	 설  명 : 세미나 참석 기록 목록 조회
         */


         	AND SMNR_ID = #{seminarId}


         	AND STD_ID = #{stdNo}

         ORDER BY FRST_INQ_DTTM DESC

mapper.insert:
		/*
             SQL ID : SeminarHstyDAO.insert
            	 설  명 : 세미나 참석 기록 등록
         */
         INSERT INTO TB_LMS_SEMINAR_HSTY (
         	  SEMINAR_HSTY_ID
			, SMNR_ID
			, STD_ID
			, ATND_SDTTM
			, CNTN_DVC_TYCD
			, USER_ID
			, RGTR_IP
			, RGTR_ID
			, FRST_INQ_DTTM
         ) VALUES (
         	  #{seminarHstyId}
         	, #{seminarId}
         	, #{stdNo}
         	, IFNULL(#{atndDttm}, FN_DTTM())
         	, #{deviceTypeCd}
         	, #{userId}
         	, #{regIp}
         	, #{rgtrId}
         	, FN_DTTM()
         )
